#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = fract(vUv);
vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw * 1 + rand_frame.xy;
vec2 d = uTexSize.zw*12;
vec3 dx = GetBlur3(vUvOriginal + vec2(1,0)*d) - GetBlur3(vUvOriginal -vec2(1,0)*d);
vec3 dy = GetBlur3(vUvOriginal + vec2(0,1)*d) - GetBlur3(vUvOriginal -vec2(0,1)*d);

vec2 uvx = vUv
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*0
           - vec2(dx.x,dy.x)*uTexSize.zw*0;
    ret.x = texture( sampler_fc_main, uvx ).x
          - (GetBlur3(uvx)-texture( sampler_fc_main, uvx )).x*0.1
          - 0.035;

vec2 uvy = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*4
           - vec2(dx.x,dy.x)*uTexSize.zw*4
           + vec2(dx.y,dy.y)*uTexSize.zw*8;

ret.y = tex2d(sampler_fc_main,uvy).y
      + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*0.1
      - 0.012
      + (tex2d(sampler_pc_main,vUvOriginal).z)*0.2;


vec2 uvz = vUvOriginal
           + (texture(sampler_noise_lq, dither_uv).xy-0.5)*uTexSize.zw*2
           + vec2(dy.x,-dx.x)*uTexSize.zw*64
           + vec2(dx.z,dy.z)*uTexSize.zw*0;
ret.z = tex2d(sampler_fc_main,uvz).z
      + (tex2d(sampler_fc_main,uvz).z-GetBlur2(uvz).z)*0.2
      + (texture(sampler_noise_lq, dither_uv).xyz)*0.1
      - GetBlur3(vUvOriginal).x
      - clamp01(1-GetBlur2(vUvOriginal).x)*0.04;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = vUv;
vUv = 0.5 + (vUv-0.5)*uAspect.xy;
rs.x = vAngle/3.14 + vRadius*(q15) - q18;
rs.y = .1/(.05+length(vUv-0.5)*1.4)+q21;

vUv = 1.0 - abs( fract( rs * 0.5 ) * 2.0 - 1.0 );
vec2 hor = vec2 (uTexSize.z,0)*4;
vec2 ver = vec2 (0,uTexSize.w)*4;
float dx = lum(GetBlur1 (vUv-hor) - GetBlur1 (vUv+hor));
float dy = lum(GetBlur1 (vUv-ver) - GetBlur1 (vUv+ver));
vec2 dz = vec2 (dx,dy);

vec3 ret1 = GetPixel(vUv);
vUv = rs;
vUv = cos(vUv*3.14*4 - vec2(0,10)*q20) - 8*dz;;
vec3 dots = clamp01(.02/length(vUv))*hue_shader;

ret = ret1;
ret = mix(mix(ret.x*vec3(2,1.2,0),vec3(0.25,0,0.5),clamp01(ret.y))
          ,1.8
          ,clamp01(ret.z-ret.x));

ret = mix(ret,dots,0.92)*6;
//ret = GetPixel(uvo);

  fragColor = ret;
}
